// UART echo - talk to serial hardware from a script.
//
// uart(tx, rx, baud) claims UART1 on any free pins; uart_send() transmits;
// complete lines come back through on_uart(line).
//
// SIMULATOR: writes loop straight back, so this works with zero wiring.
// REAL BOARD: jumper GPIO4 -> GPIO5 for the same echo, or wire a real
// device (RDM6300 TX -> GPIO5 at 9600 baud and just read tags in on_uart).

fn on_start() {
    this.n = 0;
    uart(4, 5, 115200);              // TX = GPIO4, RX = GPIO5
    uart_send("hello uart\n");
    log("uart up on TX=4 RX=5 @115200");
}

fn on_uart(line) {
    this.n += 1;
    log(`rx #${this.n}: ${line}`);
    if this.n < 5 {
        after(500, || uart_send(`ping\n`));
    }
}
